import{v as d,r as a,o as h,i as c,w as n,b as e,d as t,a as o}from"./index-6e7b20f4.js";const u={class:"markdown-body"},p=e("h1",{id:"about",tabindex:"-1"},"About",-1),m=e("h2",{id:"what-is-currently-shown-to-the-public",tabindex:"-1"},"What is currently shown to the public",-1),f=e("p",null,"This first public version of OSF presented by TaxonPages and curated in a TaxonWorks instance, displays an overview of the most relevant information of the database. The design in panels provides the option to download the data in DwC/CSV formats.",-1),g=e("p",null,"All data behind this site is served as JSON through calls to a TaxonWorks API.",-1),b=e("h2",{id:"what-will-be-shown-in-the-future",tabindex:"-1"},"What will be shown in the future",-1),y=e("p",null,"New tabs displaying the complete information of the database, as well as different search and filter options, will be progressively developed evaluating the needs of the orthopterists’ community.",-1),_=e("h2",{id:"link-to-the-old-osf",tabindex:"-1"},"Link to the old OSF",-1),v=e("p",null,[t("If you find apparent errors in this new version, please compare with the data in the old OSF powered by Species File Software, frozen since August, 14 2023. "),e("a",{href:"http://orthoptera.archive.speciesfile.org/",rel:"noopener noreferrer",target:"_blank"},"http://orthoptera.archive.speciesfile.org/"),t(". Please notify us about any incorrectly migrated data.")],-1),w=e("h2",{id:"dig-deeper-in-osf",tabindex:"-1"},"Dig deeper in OSF",-1),S=e("a",{href:"https://docs.google.com/document/d/1Ser_9uG31b-zL4YcPJrafZ19BnNCenh-S2zBcsIjLio/",rel:"noopener noreferrer",target:"_blank"},"https://docs.google.com/document/d/1Ser_9uG31b-zL4YcPJrafZ19BnNCenh-S2zBcsIjLio/",-1),k=e("h2",{id:"governance",tabindex:"-1"},"Governance",-1),T=e("p",null,"OSF is managed at three different levels, each having their own tasks and responsibilities:",-1),x=e("ol",null,[e("li",null,"the Editorial Board"),e("li",null,"the Governance Committee"),e("li",null,"the Data Management Team")],-1),C=e("h3",{id:"1.-editorial-board",tabindex:"-1"},"1. Editorial Board",-1),O=e("p",null,"The Editorial Board includes authors whose main task is to add new data based on published literature, images, and other information, as well as to correct errors in the database.",-1),F=e("h3",{id:"editorial-policy",tabindex:"-1"},"Editorial policy",-1),M=e("p",null,"The classification and nomenclature of the database reflect the most recent published information. If a change in classification depends on subjective judgment, and the matter is of sufficient interest that conflicting opinions are likely to be published; then the authors may delay entering the change until a predominant opinion emerges from multiple authors. Controversial issues are resolved by the OSF Governance Committee. However, each conflicting citation is entered with a note giving the opinion of that author.",-1),P=e("h3",{id:"2.-governance-committee",tabindex:"-1"},"2. Governance Committee",-1),B=e("p",null,"The Governance Committee members are appointed by the Director of the database with the approval of the President of the Orthopterists’ Society. The responsibilities of the committee are as follows",-1),E=e("li",null,"Review proposed changes to higher ranks within the database.",-1),I=e("li",null,"Provide advise on design of database and priorities for tasks",-1),D=e("h4",{id:"committee-members-are",tabindex:"-1"},"Committee members are",-1),N=e("ul",null,[e("li",null,"María Marta Cigliano, Division Entomología, Museo de la Plata, CEPAVE-CONICET, La Plata, Argentina"),e("li",null,"Holger Braun, Division Entomología, Museo de la Plata, La Plata, Argentina"),e("li",null,"Claudia Hemp, University of Bayreuth, Bayreuth, Germany"),e("li",null,"Sigfrid Ingrisch, Zoologisches Forschungsinstitut und Museum Alexander Koenig, Bonn, Germany"),e("li",null,"Michel Lecoq, Past President, Orthopterists’ Society; Manager, The Ted Cohn Research Fund; Subject Editor, Journal of Orthoptera Research; France"),e("li",null,"Hugh Rowell, Ayer, Switzerland"),e("li",null,"Tony Robillard, Institut Systématique Evolution Biodiversité (ISYEB), Muséum national d’Histoire naturelle, Paris, France"),e("li",null,"Hojun Song, Department of Entomology, Ecology & Evolutionary Biology IDP, Texas A&M University, College Station, Texas, USA")],-1),A=e("h3",{id:"3.-data-management-team-and-taxonworks-development",tabindex:"-1"},"3. Data Management Team and TaxonWorks development",-1),G=e("p",null,[t("The Data Management Team, the "),e("a",{href:"http://speciesfilegroup.org/about",rel:"noopener noreferrer",target:"_blank"},"Species File Group"),t(", is based at the Illinois Natural History, University of in Champaign-Urbana, Illinois, part of the Prarie Research Institute has core members and collaborators around the world. The Species File Group is responsible for developing TaxonWorks, keeping the database online, protecting its integrity.")],-1),H=e("h4",{id:"the-taxonworks-community",tabindex:"-1"},"The TaxonWorks Community",-1),L=e("p",null,[t("The work revealed on this website comes from many community meetings, many hours of research, a lot of software and data model development. This includes considerable effort to support impactful culture change and potentially enhanced standards of practice for data capture, sharing resources, knowledge, and workload. Please join the our community via the "),e("a",{href:"https://speciesfilegroup.org/events.html",rel:"noopener noreferrer",target:"_blank"},"Species File Group’s regular Wednesday meetings"),t(" to add your voice to our community and learn more.")],-1),W=e("h2",{id:"orthopterists%E2%80%99-society-community-participation",tabindex:"-1"},"Orthopterists’ Society Community participation",-1),R=e("p",null,"The underlying database of this website was prepared in cooperation with the Orthopterists’ Society. The decision to proceed in this manner was deliberate for two reasons: to provide continuity, and because of the magnitude of the job. The database should be a growing and evolving thing that continues past the careers of those who have responsibility for it from time to time. This database was started by Daniel Otte, enhanced first by Piotr Naskrecki and later by David Eades. Later, David Eades selected Maria Marta Cigliano, as his successor, approved by the OSF committee and the Board of the Orthopterists’ Society.",-1),U=e("p",null,"Members of the Orthopterists’ Society doing serious work with Orthoptera are invited to participate in making this website and database better. In most cases this will mean correcting or adding information fitting the individual’s specific research interest. Participation can be at various levels.",-1),j=e("li",null,"Submit images and/or sound recordings for inclusion in the database. The source will be acknowledged when users view images or listen to sound recordings.",-1),q=e("li",null,[t("Experts of a group are welcome to: "),e("ul",null,[e("li",null,"Review the information shown for the group and note any problems."),e("li",null,"Either edit the database over the Internet to fix any problems, or else communicate the problems to Maria Marta Cigliano. Changes to the database should conform to the editorial policy."),e("li",null,"Develop new information such as interactive keys. There are many useful ways the project could be expanded. This final level of participation requires some knowledge of computer programming and a serious time commitment. Contact Maria Marta Cigliano if you are interested.")])],-1),z=e("h2",{id:"history",tabindex:"-1"},"History",-1),J=e("p",null,"Daniel Otte, from the Academy of Natural Sciences of Philadelphia, USA, developed the initial version of the database, mostly on data from the Zoological Record. His first volume of the Orthoptera Species File was published in 1994 to cover crickets (Grylloidea). Subsequent volumes continued through volume eight in 2000 to complete all Orthoptera. The collaboration between Otte and Piotr Naskrecki led to the first version online of the Orthoptera Species File in 1997. Naskrecki and Otte also published “An Illustrated Catalog of Orthoptera, Vol. I. Tettigonioidea (Katydids or bush-crickets)” in CD-ROM format, in 1999.",-1),V=e("p",null,"David Eades, the founder of the Species File Group at Illinois Natural History Survey, USA, currently retired, with the approval of Otte and Naskrecki submitted a proposal to the Orthopterists’ Society that established the basis for version two of the Orthoptera Species File. Data from the Tettigonioidea CD-ROM was imported to a new database, the incipient Species File software, which provided cross checking of data. Import of all data from previous versions of the Orthoptera Species File was completed in July 2002. The much more complex programming required for editing the data was developed gradually while the data was being imported. New data based on the Zoological Record was brought current in September 2004. Programming to support keys and specimen data was completed in 2005. Also in 2005, Eades and Paul Brock, from the Natural History Museum, London, initiated the Phasmida Species File. Other Species Files were developed, such as Aphid Species File, Cockroach Species File, Coreoidea Species File, Lygaeoidea Species File, Psocodea Species File, Mantodea Species File, and Plecoptera Species File.",-1),Z=e("p",null,"Since March 2010, data entry responsibility has been transferred to the Museo de La Plata, Universidad Nacional de La Plata, Argentina, under the leadership of Maria Marta Cigliano and Holger Braun as the principal author.",-1),Y=e("h3",{id:"funding",tabindex:"-1"},"Funding",-1),K=e("p",null,"Work on OSF is funded by an endowment to the Orthopterists’ Society through the University of Illinois, Champaign-Urbana. The endowment provides a relatively rare environment within the field of biodiversity informatics, i.e. fixed funding for long term research and development.",-1),$={},oe="",ie=d({__name:"about",setup(Q,{expose:r}){return r({frontmatter:{},excerpt:void 0}),(X,ee)=>{const i=a("address-maker"),s=a("router-link"),l=a("markdown-layout");return h(),c(l,{frontmatter:$},{default:n(()=>[e("div",u,[p,m,f,g,b,y,_,v,w,e("p",null,[t("The TaxonWorks interfaces encompass a wide range of additional filtering and reporting functionalities. If you require extended access to the data, please reach out to us at ["),o(i,{class:"font-medium",items:["cigliano","fcnym","unlp","edu","ar"]}),t("; "),o(i,{class:"font-medium",items:["braun","fcnym","unlp","edu","ar"]}),t("]. For guidance on using filters in TaxonWorks, refer to the help document available at ["),S,t("]. Over time, we anticipate that this site will progressively incorporate the extended functionalities present in TaxonWorks. If you have any comments or questions regarding the database, you can contact María Marta Cigliano ("),o(i,{class:"font-medium",items:["cigliano","fcnym","unlp","edu","ar"]}),t(") or Holger Braun ("),o(i,{class:"font-medium",items:["braun","fcnym","unlp","edu","ar"]}),t("), or for technical inquiries, reach out to Hernán Pereira ("),o(i,{class:"font-medium",items:["ellocodelassembler","gmail","com"]}),t(") or José Pereira ("),o(i,{class:"font-medium",items:["pepelui","outlook","com"]}),t(").")]),k,T,x,C,O,F,M,P,B,e("ul",null,[e("li",null,[t("Grant awards from the endowment (currently about US$30,000 each year). The Orthopterists’ Society, through the OSF, has funds available for supporting database work in varying amounts from year to year. For more information please refer to the "),o(s,{to:"grants"},{default:n(()=>[t("grant application guidelines")]),_:1}),t(". The Orthoptera Species File Committee is responsible for determining the recipients of such funds.")]),E,I]),D,N,A,G,H,L,W,R,U,e("ul",null,[e("li",null,[t("Communicate comments, suggestions and corrections to Maria Marta Cigliano (send mail "),o(i,{class:"font-medium",items:["cigliano","fcnym","unlp","edu","ar"]}),t(").")]),e("li",null,[t("Notify about publications to Holger Braun (send mail "),o(i,{class:"font-medium",items:["braun","fcnym","unlp","edu","ar"]}),t(") for incorporation of data into the database.")]),j,q]),z,J,V,Z,Y,K])]),_:1})}}});export{ie as default,oe as excerpt,$ as frontmatter};
